    ('(?i)\\b(sessionId|session_token)\\b.{0,40}\\b(?:steal|capture|inject|reuse)\\b', 'low', 'mcp-session-hijacking-id-theft: Detects session hijacking attacks (TV21) by identifying session ID capture or injection.'),
    ('(?i)\\bhijackSession\\b', 'low', 'mcp-session-hijacking-id-theft: Detects session hijacking attacks (TV21) by identifying session ID capture or injection.'),
    ('(?i)\\bstealSession\\b', 'low', 'mcp-session-hijacking-id-theft: Detects session hijacking attacks (TV21) by identifying session ID capture or injection.'),
