    ('(?i)(?:session|token)_(?:hijack|steal|reuse)\\s*=\\s*[\'"]', 'low', 'mcp-session-hijacking-harness: Session hijacking harness that intercepts and reuses MCP session tokens to impersonate legitimate agents.'),
