    ('(?i)\\bsession_token\\s*=\\s*[\'"]?\\d{4,10}[\'"]?', 'high', 'mcp-session-hijacking-id-theft-scanner: Detection of session token or ID patterns that are static or predictable, enabling session hijacking'),
    ('(?i)(?:env|config|setting).{0,40}(?:MCP_TOKEN|MCP_SECRET|MCP_API_KEY)\\s*[:=]\\s*[\'"][^\'"]{3,}[\'"]', 'high', 'mcp-session-hijacking-token-exposure-config: Detects misconfigurations that expose session tokens or credentials in MCP configuration files.'),
    ('(?i)(?:session[_-]?id|token|api[_-]?key|secret)\\s*[=:]\\s*[\'"]([a-zA-Z0-9+/=]{20,})[\'"]', 'low', 'mcp-session-hijacking-token-exposure-config: Detects exposure of session identifiers or tokens in MCP server configurations or logs, as in D'),
    ('(?i)MCP_SESSION_TOKEN\\s*[=:]\\s*[\'"][^\'"]+[\'"]', 'low', 'mcp-session-hijacking-token-exposure-config: Detects exposure of session identifiers or tokens in MCP server configurations or logs, as in D'),
    ('(?i)(?:export|set)\\s+MCP[_-]?(?:SESSION|AUTH)[_-]?TOKEN\\s*[=:]', 'low', 'mcp-session-hijacking-token-exposure-config: Detects exposure of session identifiers or tokens in MCP server configurations or logs, as in D'),
    ('(?i)\\b(?:session_id|token|api_key)\\s*[:=]\\s*\\w+[\'"]?\\s*.{0,40}\\b(?:log|print|emit)\\b', 'critical', 'mcp-session-hijacking-token-exposure-logging: Detects logging of session tokens or credentials in MCP server requests (Piazza 2025).'),
