    ('(?i)\\b(?:session_id|token|api_key|secret_key)\\s*[=:]\\s*[\'"](?:\\w+)\\b.{0,60}(?:log|print|return)', 'medium', 'mcp-session-hijacking-credential-leak: Detects code that exposes session tokens or credentials via MCP tool outputs or logs, enabling sessio'),
    ('(?i)(?:resource|tool)\\.(?:get|read|fetch)\\s*\\([^)]{0,200}\\)[\\s\\S]{0,200}(?:log|print|dump)\\s*\\([^)]{0,200}\\)', 'low', 'mcp-session-hijacking-credential-log-exposure: Detects logging of session tokens, credentials, or API keys from MCP resource or tool outputs'),
    ('(?i)"session"\\s*:\\s*\\{[^}]*"token"\\s*:\\s*"[^"]*"', 'low', 'mcp-session-hijacking-token-exposure-scanner: Detects MCP server configurations that expose session identifiers or tokens in metadata or too'),
    ('(?i)"parameter"\\s*:\\s*"(?:session_id|token|api_key|secret|auth)"', 'low', 'mcp-session-hijacking-token-exposure-scanner: Detects MCP server configurations that expose session identifiers or tokens in metadata or too'),
    ('(?i)"(?:output|response)"\\s*:\\s*\\{[^}]*"session"\\s*:\\s*"[^"]*"', 'low', 'mcp-session-hijacking-token-exposure-scanner: Detects MCP server configurations that expose session identifiers or tokens in metadata or too'),
    ('(?i)env\\.(?:get|fetch).{0,40}[\'"](?:MCP_SESSION|MCP_TOKEN|API_KEY|SECRET)[\'"]', 'high', 'mcp-session-hijacking-token-exposure: Detects exposure of session tokens or credentials in MCP server code.'),
    ('(?i)(?:session_token|session_id|auth_token|bearer).{0,20}="?[A-Za-z0-9+/]{40,}={0,2}"?', 'high', 'mcp-session-hijacking-token-in-config: Detects MCP configuration files containing exposed session tokens or API keys (Piazza, 2025).'),
    ('(?i)(?:Authorization|X-API-Key|Bearer)\\s*[:=]\\s*[\'"](?:session|token|secret)[^\'"]*[\'"]', 'critical', 'mcp-session-hijacking-token-in-header: Detects MCP server code that exposes session tokens or credentials in HTTP headers without encryption'),
    ('(?i)headers\\[.{0,40}[\'"](?:auth|token|session)[\'"].{0,40}=.{0,40}(?:request|user|get)', 'critical', 'mcp-session-hijacking-token-in-header: Detects MCP server code that exposes session tokens or credentials in HTTP headers without encryption'),
    ('(?i)(?:from|import)\\s+mcp_session_token\\b', 'high', 'mcp-session-hijacking-token-exposure-code: Detects code that exposes MCP session tokens or identifiers without strict access controls, enabl'),
    ('(?i)session_token\\s*=\\s*[\'"][^\'"]{16,}[\'"]', 'high', 'mcp-session-hijacking-token-exposure-code: Detects code that exposes MCP session tokens or identifiers without strict access controls, enabl'),
    ('(?i)(?:session[_-]token|access[_-]token|api[_-]key|bearer).{0,60}(?:log|print|console|write|dump)', 'medium', 'mcp-session-hijacking-token-in-log: Detects exposure of session tokens or credentials in MCP logs, which could facilitate session hijacking '),
    ('(?i)(?:capture|steal|hijack|sniff).{0,12}(?:session|token)', 'high', 'mcp-session-hijacking-token-exposure: Detects MCP server code that exposes or uses insecure session identifiers, enabling session hijacking '),
